gold_sparql:
PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX wd:   <http://www.wikidata.org/entity/>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX ts:   <https://linkedmusic.ca/graphs/thesession/>
SELECT ?session
WHERE {
  GRAPH ts: {
    ?session a ts:Session ;
             wdt:P17 wd:Q41 .
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX wd:   <http://www.wikidata.org/entity/>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX mb:   <https://linkedmusic.ca/graphs/musicbrainz/>
SELECT ?recording
WHERE {
  GRAPH mb: {
    ?artist a mb:Artist .
    ?artist wdt:P2888 wd:Q93341 .
    ?recording a mb:Recording .
    ?recording wdt:P175 ?artist .
  }
}

PREFIX wd:   <http://www.wikidata.org/entity/>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX cdb:  <https://linkedmusic.ca/graphs/cantusdb/>
SELECT ?chant
WHERE {
  GRAPH cdb: {
    ?chant wdt:P826 wd:Q735435 .
  }
}

PREFIX wd:    <http://www.wikidata.org/entity/>
PREFIX wdt:   <http://www.wikidata.org/prop/direct/>
PREFIX rism:  <https://linkedmusic.ca/graphs/rism/>
SELECT ?source
WHERE {
  GRAPH rism: {
    ?source wdt:P276 ?institution .
    ?institution wdt:P2888 wd:Q23308 .
  }
}

PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX cdb:  <https://linkedmusic.ca/graphs/cantusdb/>
SELECT ?mode (COUNT(?chant) AS ?chantCount)
WHERE {
  GRAPH cdb: {
    ?chant wdt:P826 ?mode .
  }
}
GROUP BY ?mode
ORDER BY DESC(?chantCount)

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX ts:   <https://linkedmusic.ca/graphs/thesession/>
SELECT ?country (COUNT(?session) AS ?sessionCount)
WHERE {
  GRAPH ts: {
    ?session a ts:Session ;
             wdt:P17 ?country .
  }
}
GROUP BY ?country
ORDER BY DESC(?sessionCount)
LIMIT 10

PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt:   <http://www.wikidata.org/prop/direct/>
PREFIX rism:  <https://linkedmusic.ca/graphs/rism/>
SELECT ?composer ?composerLabel (COUNT(?source) AS ?sourceCount)
WHERE {
  GRAPH rism: {
    ?source wdt:P86 ?composer .
    ?composer rdfs:label ?composerLabel .
  }
}
GROUP BY ?composer ?composerLabel
HAVING (COUNT(?source) > 50)
ORDER BY DESC(?sourceCount)

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd:   <http://www.wikidata.org/entity/>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX mb:   <https://linkedmusic.ca/graphs/musicbrainz/>
SELECT ?artist ?artistLabel
WHERE {
  {
    SELECT ?artist ?artistLabel ?artistWikidata
    WHERE {
      GRAPH mb: {
        ?artist a mb:Artist ;
                rdfs:label ?artistLabel ;
                wdt:P2888 ?artistWikidata .
      }
    }
  }
  SERVICE <https://query.wikidata.org/sparql> {
    ?artistWikidata wdt:P19 wd:Q84 .
  }
}

PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt:   <http://www.wikidata.org/prop/direct/>
PREFIX diamm: <https://linkedmusic.ca/graphs/diamm/>
SELECT ?composition ?compositionLabel ?composer ?composerLabel
WHERE {
  {
    SELECT ?composition ?compositionLabel ?composer ?composerLabel ?composerWikidata
    WHERE {
      GRAPH diamm: {
        ?composition a diamm:Composition ;
                     rdfs:label ?compositionLabel ;
                     wdt:P86 ?composer .
        ?composer rdfs:label ?composerLabel ;
                  wdt:P2888 ?composerWikidata .
      }
    }
  }
  SERVICE <https://query.wikidata.org/sparql> {
    ?composerWikidata wdt:P569 ?birthDate .
    FILTER (YEAR(?birthDate) < 1400)
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX wd:   <http://www.wikidata.org/entity/>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX gj:   <https://linkedmusic.ca/graphs/theglobaljukebox/>
SELECT DISTINCT ?song
WHERE {
  {
    SELECT ?song ?country
    WHERE {
      GRAPH gj: {
        ?song a gj:Song .
        ?song wdt:P2596 ?culture .
        ?culture wdt:P17 ?country .
      }
    }
  }
  SERVICE <https://query.wikidata.org/sparql> {
    ?country wdt:P30 wd:Q48 .
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX ts:   <https://linkedmusic.ca/graphs/thesession/>
SELECT ?country ?countryLabel ?population
WHERE {
  {
    SELECT DISTINCT ?country
    WHERE {
      GRAPH ts: {
        ?event a ts:Events ;
               wdt:P17 ?country .
      }
    }
  }
  SERVICE <https://query.wikidata.org/sparql> {
    ?country rdfs:label ?countryLabel .
    ?country wdt:P1082 ?population .
    FILTER (LANG(?countryLabel) = "en")
  }
}
ORDER BY DESC(?population)

PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt:   <http://www.wikidata.org/prop/direct/>
PREFIX diamm: <https://linkedmusic.ca/graphs/diamm/>
PREFIX rism:  <https://linkedmusic.ca/graphs/rism/>
SELECT DISTINCT ?composition ?compositionLabel ?composer ?composerLabel
WHERE {
  GRAPH diamm: {
    ?composition a diamm:Composition ;
                 rdfs:label ?compositionLabel ;
                 wdt:P86 ?composer .
    ?composer rdfs:label ?composerLabel ;
              wdt:P2888 ?wikidata .
  }
  GRAPH rism: {
    ?rismComposer wdt:P2888 ?wikidata .
    ?rismSource wdt:P86 ?rismComposer .
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ts:   <https://linkedmusic.ca/graphs/thesession/>
PREFIX mb:   <https://linkedmusic.ca/graphs/musicbrainz/>
SELECT DISTINCT ?recording ?tuneLabel ?work ?workLabel
WHERE {
  GRAPH ts: {
    ?recording a ts:Recording ;
               wdt:P658 ?tune .
    ?tune rdfs:label ?tuneLabel .
  }
  GRAPH mb: {
    ?work a mb:Work ;
          rdfs:label ?workLabel .
  }
  FILTER (LCASE(STR(?tuneLabel)) = LCASE(STR(?workLabel)))
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX dtl:  <https://linkedmusic.ca/graphs/dig-that-lick/>
PREFIX mb:   <https://linkedmusic.ca/graphs/musicbrainz/>
SELECT DISTINCT ?track ?trackLabel ?artist
WHERE {
  GRAPH dtl: {
    ?track a dtl:Track ;
           rdfs:label ?trackLabel ;
           wdt:P175 ?wikidataArtist .
  }
  GRAPH mb: {
    ?mbArtist a mb:Artist ;
              wdt:P2888 ?wikidataArtist .
    ?recording a mb:Recording ;
               wdt:P175 ?mbArtist .
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX gj:   <https://linkedmusic.ca/graphs/theglobaljukebox/>
PREFIX rism:  <https://linkedmusic.ca/graphs/rism/>
SELECT DISTINCT ?culture ?cultureLabel
WHERE {
  GRAPH gj: {
    ?culture a gj:Culture ;
             rdfs:label ?cultureLabel ;
             wdt:P17 ?country .
  }
  GRAPH rism: {
    ?institution a rism:Institution ;
                 wdt:P2888 ?country .
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ts:   <https://linkedmusic.ca/graphs/thesession/>
SELECT ?tune ?tuneLabel
WHERE {
  GRAPH ts: {
    ?tune a ts:Tune ;
          rdfs:label ?tuneLabel .
    FILTER (CONTAINS(LCASE(STR(?tuneLabel)), "reel"))
  }
}

PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>
PREFIX diamm: <https://linkedmusic.ca/graphs/diamm/>
SELECT ?person ?personLabel
WHERE {
  GRAPH diamm: {
    ?person a diamm:Person ;
            rdfs:label ?personLabel .
    FILTER (CONTAINS(LCASE(STR(?personLabel)), "bach"))
  }
}

PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt:   <http://www.wikidata.org/prop/direct/>
PREFIX diamm: <https://linkedmusic.ca/graphs/diamm/>
SELECT ?composition ?label
WHERE {
  GRAPH diamm: {
    ?composition a diamm:Composition ;
                 rdfs:label ?label .
    FILTER NOT EXISTS {
      ?composition wdt:P136 ?genre .
    }
  }
}

PREFIX rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt:  <http://www.wikidata.org/prop/direct/>
PREFIX mb:   <https://linkedmusic.ca/graphs/musicbrainz/>
SELECT ?artist ?artistLabel ?birthDate
WHERE {
  GRAPH mb: {
    ?artist a mb:Artist ;
            rdfs:label ?artistLabel .
    OPTIONAL {
      ?artist wdt:P569 ?birthDate .
    }
  }
}
LIMIT 100
